import { Component, Prop, State, Event, EventEmitter, h, Watch } from '@stencil/core';
import moment, { Moment } from 'moment';

export interface DateRange {
  from: Moment | null;
  to: Moment | null;
}
export interface QuickDatePreset {
  label: string;
  getDate: () => Moment;
}
@Component({
  tag: 'ir-date-range-filter',
  styleUrl: 'ir-date-range-filter.css',
  scoped: true,
})
export class IrDateRangeFilter {
  /** Quick date preset buttons */
  @Prop() quickDates: QuickDatePreset[] = [
    { label: 'Today', getDate: () => moment() },
    { label: '30 Days Ago', getDate: () => moment().subtract(30, 'days') },
    { label: '60 Days Ago', getDate: () => moment().subtract(60, 'days') },
    { label: '90 Days Ago', getDate: () => moment().subtract(90, 'days') },
    { label: '1 Year Ago', getDate: () => moment().subtract(1, 'year') },
  ];

  /** Controlled start date (YYYY-MM-DD) */
  @Prop() fromDate?: string;

  /** Controlled end date (YYYY-MM-DD) */
  @Prop() toDate?: string;

  @Prop({ reflect: true }) size = 'small';

  /** Show quick action buttons */
  @Prop() showQuickActions: boolean = true;

  @State() dates: DateRange = { from: null, to: null };
  @State() liveMessage: string = '';

  @Event() datesChanged: EventEmitter<{ from: string | null; to: string | null }>;

  private groupId = `date-range-${Math.random().toString(36).substring(2, 9)}`;
  toDateSelectRef: HTMLIrDateSelectElement;
  fromDateSelectRef: HTMLIrDateSelectElement;

  componentWillLoad() {
    this.dates = {
      from: this.fromDate ? moment(this.fromDate) : null,
      to: this.toDate ? moment(this.toDate) : null,
    };
  }

  @Watch('fromDate')
  onFromDateChange(newValue: string) {
    this.dates = { ...this.dates, from: newValue ? moment(newValue) : null };
  }

  @Watch('toDate')
  onToDateChange(newValue: string) {
    this.dates = { ...this.dates, to: newValue ? moment(newValue) : null };
  }

  private selectDate(date: Moment, type: 'from' | 'to') {
    const { from, to } = this.dates;

    let updated: DateRange = { ...this.dates };

    if (type === 'from') {
      if (to && date.isAfter(to, 'day')) {
        updated = {
          from: date,
          to: date.clone().add(1, 'day'),
        };
      } else {
        updated.from = date;
      }
    }

    if (type === 'to') {
      if (from && date.isBefore(from, 'day')) {
        updated.to = from.clone();
      } else {
        updated.to = date;
      }
    }

    this.dates = updated;

    this.emitChange();

    if (type === 'from') {
      requestAnimationFrame(() => this.toDateSelectRef?.openDatePicker());
    }
  }

  private emitChange() {
    const from = this.dates.from ? this.dates.from.format('YYYY-MM-DD') : null;

    const to = this.dates.to ? this.dates.to.format('YYYY-MM-DD') : null;

    this.datesChanged.emit({ from, to });

    this.liveMessage = `Date range updated. From ${from ?? 'not set'} to ${to ?? 'not set'}.`;
  }

  render() {
    const fromLabel = this.dates?.from ? this.dates.from.format('MMM D, YYYY') : null;
    const toLabel = this.dates?.to ? this.dates.to.format('MMM D, YYYY') : null;

    return (
      <div class="date-ranger-filters__dates" role="group" aria-labelledby={`${this.groupId}-label`}>
        <span id={`${this.groupId}-label`} class="sr-only">
          Date range selector
        </span>

        <wa-icon name="calendar" variant="regular" class="date-ranger-filters__cal-icon"></wa-icon>

        {/* FROM */}
        <ir-date-select
          data-type="from"
          ref={el => (this.fromDateSelectRef = el)}
          date={this.dates?.from?.format('YYYY-MM-DD')}
          placeholder="From"
          aria-label="Start date"
          class="date-ranger-filters__date-select --from"
          onDateChanged={evt => this.selectDate(evt.detail.start, 'from')}
        >
          <button slot="trigger" class="date-range-filters__date-select-trigger" aria-label={fromLabel ?? 'Select start date'}>
            {fromLabel ?? <span class="date-range-filters__placeholder">From</span>}
          </button>
          {this.showQuickActions && (
            <div class="date-ranger-filters__quick-actions" role="group" aria-label="Quick start date options">
              {this.quickDates.map(action => (
                <ir-custom-button
                  type="button"
                  variant="neutral"
                  appearance="outlined"
                  aria-label={`Set start date to ${action.label}`}
                  onClickHandler={() => this.selectDate(action.getDate(), 'from')}
                >
                  {action.label}
                </ir-custom-button>
              ))}
            </div>
          )}
        </ir-date-select>

        <span class="date-ranger-filters__arrow" aria-hidden="true">&#8594;</span>

        {/* TO */}
        <ir-date-select
          data-type="to"
          date={this.dates?.to?.format('YYYY-MM-DD')}
          minDate={this.dates?.from?.format('YYYY-MM-DD')}
          placeholder="To"
          aria-label="End date"
          ref={el => (this.toDateSelectRef = el)}
          class="date-ranger-filters__date-select --to"
          onDateChanged={evt => this.selectDate(evt.detail.start, 'to')}
          onDatePickerFocus={e => {
            e.stopImmediatePropagation();
            e.stopPropagation();
            if (!this.dates?.from) {
              requestAnimationFrame(() => {
                this.toDateSelectRef.closeDatePicker();
              });
              requestAnimationFrame(() => {
                this.fromDateSelectRef.openDatePicker();
              });
            }
          }}
        >
          <button slot="trigger" class="date-range-filters__date-select-trigger" aria-label={toLabel ?? 'Select end date'}>
            {toLabel ?? <span class="date-range-filters__placeholder">To</span>}
          </button>
          {this.showQuickActions && (
            <div class="date-ranger-filters__quick-actions" role="group" aria-label="Quick end date options">
              {this.quickDates.map(action => (
                <ir-custom-button
                  type="button"
                  variant="neutral"
                  appearance="outlined"
                  aria-label={`Set end date to ${action.label}`}
                  onClickHandler={() => this.selectDate(action.getDate(), 'to')}
                >
                  {action.label}
                </ir-custom-button>
              ))}
            </div>
          )}
        </ir-date-select>

        {/* Live Region */}
        <span aria-live="polite" aria-atomic="true" class="sr-only">
          {this.liveMessage}
        </span>
      </div>
    );
  }
}
